function clear02() {
	document.holder.result.value = "",
	document.holder.cent_freq.selectedIndex = 0,
	document.holder.freq.readOnly = 0,
	document.holder.freq.style.background = "#ffffff"
} function calc() {
	var e = 1 * document.holder.freq.value,
	t = 1 * document.holder.impedance.value,
	C = 0; 
	document.holder.measure && (C = 1 * document.holder.measure.value),
		document.holder.result.value = solveHarchenko(e,
			t,
			C
		)
} function solveHarchenko(e,
	t,
	C) {
		let A = new CommonLanguageHelper,
		H = new HarchenkoLanguageHelper,
		_ = ""; if (e > 0) {
			let o = 299792.458 / e,
			n = [1.02632601918224,
				.180628960318941],
			L = [1.02632601918224,
				.147486031820053],
			a = [.138647917553682,
				.218190945951014,
				.452953356151472,
				.671144302102486],
			i = [.138647917553682,
				.204381392409811,
				.452953356151472,
				.662858569977764],
			K = .12033644955805,
			E = .0099,
			l = 1.3962634015954636,
			s = LocaleUtils.getActualWireDiam(E * o); 
			if (_ = "Javascript Version 2025-08-19 by 3G-Aerial\n",
				s > 0) {
					let E = K * o,
					h = 0,
					r = 0,
					R = 0,
					c = 0,
					N = 0,
					O = 0,
					f = 0; 50 == t ? (h = (i[3] + K) * o,
						r = (i[1] + K) * o,
						R = L[1] * o - .4,
						c = i[0] * o,
						N = i[1] * o,
						O = i[2] * o,
						f = i[3] * o) : (h = (a[3] + K) * o,
							r = (a[1] + K) * o,
							R = n[1] * o - .4,
							c = a[0] * o,
							N = a[1] * o,
							O = a[2] * o,
							f = a[3] * o); let m = n[0] * o,
								g = Math.sqrt(Math.pow(c / 2 - E * Math.cos(l / 2) / 2 - (N / 2 + E * Math.cos(l / 2) / 2),
									2) + Math.pow(E * Math.sin(l / 2) / 2 - (O / 2 - E * Math.sin(l / 2) / 2),
										2)),
								u = Math.sqrt(Math.pow(N / 2 + E * Math.cos(l / 2) / 2 - E * Math.cos(l / 2) / 2,
									2) + Math.pow(O / 2 + E * Math.sin(l / 2) / 2 - (f / 2 + E * Math.sin(l / 2) / 2),
										2)),
								d = Math.PI * E / 3,
								T = 5 * Math.PI * E / 36,
								I = 4 * (g + u + d + T),
								G = LocaleUtils.converttoAWG(s),
								p = 0; e > 600 && e <= 1200 ? p = 1 : e > 1200 && e <= 2e3 ? p = 2 : e > 2e3 && (p = 3),
									_ += H.CALC_KHARCHENKO_TITLE + "\n",
									_ += "-------------------------------------------------------------\n",
									_ += A.CALC_KHARCHENKO_FREQ + " f: " + e + A.CALC_MHZ + "\n",
									_ += A.CALC_INPUT_IMPEDANCE + " Zo: " + t + " Ω\n",
									_ += A.CALC_WAVELENGTH + " λ: " + LocaleUtils.formatLength(o,
										C,
										p) + "\n",
									_ += "-------------------------------------------------------------\n",
									_ += H.CALC_KHARCHENKO_BIQUAD_LENGTH + ": " + LocaleUtils.formatLength(h,
										C,
										p) + "\n",
									_ += H.CALC_KHARCHENKO_BIQUAD_WIDTH + ": " + LocaleUtils.formatLength(r,
										C,
										p) + "\n",
									_ += H.CALC_KHARCHENKO_PERIMETER + ": " + LocaleUtils.formatLength(I,
										C,
										p) + "\n",
									_ += H.CALC_KHARCHENKO_OFFSET + " D: " + LocaleUtils.formatLength(R,
										C,
										p) + "\n",
									_ += "-------------------------------------------------------------\n",
									_ += H.CALC_KHARCHENKO_REFL_WIDTH + ": " + LocaleUtils.formatLength(m,
										C,
										p) + "\n",
									_ += H.CALC_KHARCHENKO_REFL_LENGTH + ": " + LocaleUtils.formatLength(m,
										C,
										p) + "\n",
									_ += H.CALC_KHARCHENKO_WIRE_DIAMETER + ": " + LocaleUtils.formatLength(s,
										C,
										p) + " (" + G + " AWG#)\n",
									_ += H.CALC_KHARCHENKO_QS + " qs1: " + LocaleUtils.formatLength(g + 2 * d / 3,
										C,
										p) + "\n",
									_ += H.CALC_KHARCHENKO_QS + " qs2: " + LocaleUtils.formatLength(u + T + d / 3,
										C,
										p) + "\n",
									_ += H.CALC_KHARCHENKO_R + " R: " + LocaleUtils.formatLength(E / 2,
										C,
										p) + "\n",
									_ += H.CALC_KHARCHENKO_GAP + " gap: " + LocaleUtils.formatLength(c - E - s,
										C,
										p) + "\n",
									_ += "-------------------------------------------------------------\n",
									_ += H.CALC_KHARCHENKO_G + " G0: " + LocaleUtils.formatLength(c,
										C,
										p) + "\n",
									_ += H.CALC_KHARCHENKO_G + " G1: " + LocaleUtils.formatLength(N,
										C,
										p) + "\n",
									_ += H.CALC_KHARCHENKO_G + " G2: " + LocaleUtils.formatLength(O,
										C,
										p) + "\n",
									_ += H.CALC_KHARCHENKO_G + " G3: " + LocaleUtils.formatLength(f,
										C,
										p) + "\n",
									_ += H.CALC_KHARCHENKO_GD + " GD: " + LocaleUtils.formatLength(E - s,
										C,
										p) + "\n"
			} else _ = A.CALC_KHARCHENKO_ALERT + "\n"
		} else _ = A.CALC_ALERT + "\n"; return _
} class HarchenkoLanguageHelper {
	constructor() {
		this.lng = document.documentElement.lang,
		"en-gb" == this.lng ? (this.CALC_KHARCHENKO_TITLE = "BiQuad antenna",
			this.CALC_KHARCHENKO_FREQ = "Mean frequency of the range",
			this.CALC_KHARCHENKO_BIQUAD_LENGTH = "Size W (total length of loops)",
			this.CALC_KHARCHENKO_BIQUAD_WIDTH = "Size H (width of loops)",
			this.CALC_KHARCHENKO_PERIMETER = "Total wire length (perimeter of 2 loops)",
			this.CALC_KHARCHENKO_OFFSET = "Distance from loops to the reflector",
			this.CALC_KHARCHENKO_REFL_WIDTH = "Dimension B (reflector width)",
			this.CALC_KHARCHENKO_REFL_LENGTH = "Dimension A (reflector length)",
			this.CALC_KHARCHENKO_WIRE_DIAMETER = "Wire diameter of the loops",
			this.CALC_KHARCHENKO_QS = "Approximate loop side length",
			this.CALC_KHARCHENKO_R = "Approximate wire bending radius",
			this.CALC_KHARCHENKO_GAP = "Approximate gap at connection point",
			this.CALC_KHARCHENKO_G = "Distance between guides",
			this.CALC_KHARCHENKO_GD = "Guide diameter",
			this.CALC_KHARCHENKO_ALERT = "The operating frequency is beyond the capabilities of this calculator") : (this.CALC_KHARCHENKO_TITLE = "Антенна Харченко (зигзагообразная)",
				this.CALC_KHARCHENKO_FREQ = "Центральная частота",
				this.CALC_KHARCHENKO_BIQUAD_LENGTH = "Размер W (общая длина рамок)",
				this.CALC_KHARCHENKO_BIQUAD_WIDTH = "Размер H (ширина рамок)",
				this.CALC_KHARCHENKO_PERIMETER = "Общая длина проволоки (периметр 2-х рамок)",
				this.CALC_KHARCHENKO_OFFSET = "Расстояние от рефлектора до плоскости вибратора",
				this.CALC_KHARCHENKO_REFL_WIDTH = "Размер B (ширина рефлектора)",
				this.CALC_KHARCHENKO_REFL_LENGTH = "Размер A (длина рефлектора)",
				this.CALC_KHARCHENKO_WIRE_DIAMETER = "Диаметр проволоки вибратора",
				this.CALC_KHARCHENKO_QS = "Приблизительная длина стороны рамки",
				this.CALC_KHARCHENKO_R = "Приблизительный радиус изгиба проволоки",
				this.CALC_KHARCHENKO_GAP = "Приблизительный промежуток в месте подключения",
				this.CALC_KHARCHENKO_G = "Расстояние между направляющими",
				this.CALC_KHARCHENKO_GD = "Диаметр направляющей",
				this.CALC_KHARCHENKO_ALERT = "Рабочая частота находится за пределами возможностей этого калькулятора")
	}
}

